<?php
namespace App\Services\Notifications;
use App\Models\Notifications\{NotificationCampaign,NotificationCampaignRun};
class CampaignService { public function __construct(private NotificationService $notifications, private NotificationAudienceService $audiences){} public function runCampaign(NotificationCampaign $campaign):NotificationCampaignRun{ $run=NotificationCampaignRun::create(['campaign_id'=>$campaign->id,'run_type'=>'scheduled','status'=>'running','started_at'=>now()]); if(!$campaign->is_active){$run->update(['status'=>'skipped','finished_at'=>now()]); return $run;} $users=$this->audienceFor($campaign); $sent=0;$skipped=0; foreach($users as $user){$n=$this->notifications->sendToUser($user,$campaign->code,$this->notifications->renderTemplate($campaign->title_template,['name'=>$user->name??'Peer']),$this->notifications->renderTemplate($campaign->body_template,['name'=>$user->name??'Peer']),['screen'=>$campaign->tap_screen,'campaign_id'=>$campaign->id],['campaign'=>$campaign,'channel'=>$campaign->channel,'priority'=>$campaign->priority,'screen'=>$campaign->tap_screen,'dedupe_key'=>$campaign->code.':'.$user->id.':'.now()->toDateString()]); $n?$sent++:$skipped++;} $run->update(['status'=>'finished','audience_count'=>$users->count(),'sent_count'=>$sent,'skipped_count'=>$skipped,'finished_at'=>now()]); return $run;} private function audienceFor(NotificationCampaign $campaign){return match($campaign->audience_type){'inactive_users'=>$this->audiences->inactiveUsers(), 'incomplete_profile'=>$this->audiences->incompleteProfileUsers(), 'non_pro_users'=>$this->audiences->nonProUsers(), 'subscription_expiring'=>$this->audiences->subscriptionExpiringUsers(), 'unclaimed_coins'=>$this->audiences->usersWithUnclaimedCoins(), default=>\App\Models\User::limit(100)->get()};} public function runRequirementLeadCampaign(){return $this->runByCode('requirement_lead');} public function runPendingRequirementReminder(){return $this->runByCode('pending_requirement_reminder');} public function runCircleActivityCampaign(){return $this->runByCode('circle_activity');} public function runPeopleToConnectCampaign(){return $this->runByCode('people_to_connect');} public function runUpcomingEventReminderCampaign(){return $this->runByCode('upcoming_event_reminder');} public function runEventStartingNowCampaign(){return $this->runByCode('event_starting_now');} public function runPostEventFeedbackCampaign(){return $this->runByCode('post_event_feedback');} public function runUnclaimedCoinsCampaign(){return $this->runByCode('unclaimed_coins');} public function runReferralTestimonialRewardCampaign(){return $this->runByCode('referral_testimonial_reward');} public function runWeeklyDigestCampaign(){return $this->runByCode('weekly_digest');} private function runByCode(string $code){$c=NotificationCampaign::where('code',$code)->first(); return $c?$this->runCampaign($c):null;} }
